#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *a = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&a[i]);
        if(N<=2){
            for(int i=0;i<N;i++) printf("%d%s",a[i], i+1==N?"\n":" ");
            free(a); continue;
        }
        qsort(a,N,sizeof(int),cmp);
        int maxFreq=1, cur=1;
        for(int i=1;i<N;i++){
            if(a[i]==a[i-1]) cur++; else{ if(cur>maxFreq) maxFreq=cur; cur=1; }
        }
        if(cur>maxFreq) maxFreq=cur;
        if(maxFreq > N/2){ printf("-1\n"); free(a); continue; }
        int k = N/2;
        int *res = (int*)malloc(N*sizeof(int));
        int idx=0;
        for(int i=0;i<k;i++){
            res[idx++] = a[k+i];
            res[idx++] = a[i];
        }
        if(N%2) res[idx++] = a[N-1];
        for(int i=0;i<N;i++) printf("%d%s",res[i], i+1==N?"\n":" ");
        free(a); free(res);
    }
    return 0;
}

