import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long[] a = new long[N];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) a[i] = Long.parseLong(st.nextToken());
            if (N <= 2) {
                for (int i = 0; i < N; i++) out.append(a[i]).append(i + 1 == N ? '\n' : ' ');
                continue;
            }
            Arrays.sort(a);
            int maxFreq = 1, cur = 1;
            for (int i = 1; i < N; i++) {
                if (a[i] == a[i - 1]) cur++; else { maxFreq = Math.max(maxFreq, cur); cur = 1; }
            }
            maxFreq = Math.max(maxFreq, cur);
            if (maxFreq > N / 2) {
                out.append(-1).append('\n');
                continue;
            }
            int k = N / 2;
            List<Long> res = new ArrayList<>(N);
            for (int i = 0; i < k; i++) {
                res.add(a[k + i]);
                res.add(a[i]);
            }
            if (N % 2 == 1) res.add(a[N - 1]);
            for (int i = 0; i < N; i++) out.append(res.get(i)).append(i + 1 == N ? '\n' : ' ');
        }
        System.out.print(out.toString());
    }
}

