#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        if N <= 2:
            out_lines.append(' '.join(map(str, a)))
            continue
        a.sort()
        max_freq = 1
        cur = 1
        for i in range(1, N):
            if a[i] == a[i-1]:
                cur += 1
            else:
                max_freq = max(max_freq, cur)
                cur = 1
        max_freq = max(max_freq, cur)
        if max_freq > N // 2:
            out_lines.append('-1')
            continue
        k = N // 2
        res = []
        for i in range(k):
            res.append(a[k + i])
            res.append(a[i])
        if N % 2:
            res.append(a[-1])
        out_lines.append(' '.join(map(str, res)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

